                neighbor.g = ng;
                neighbor.h = dist[y * width + x];
                neighbor.f = ng + neighbor.h;
                neighbor.parent = node;

                if (!neighbor.opened) {
                    openList.push(neighbor);
                    neighbor.opened = true;
                } else {
                    openList.updateItem(neighbor);
                }
            }
        }
    }

    return [];
};

module.exports = DijkstraFinder;
